import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Cài Đặt Fabric","description":"Bộ hướng dẫn từng bước để cài đặt Fabric.","frontmatter":{"title":"Cài Đặt Fabric","description":"Bộ hướng dẫn từng bước để cài đặt Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"1.21.10/translated/vi_vn/players/installing-fabric.md","filePath":"versions/1.21.10/translated/vi_vn/players/installing-fabric.md","lastUpdated":1766682904000}`);var c={name:`1.21.10/translated/vi_vn/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Cài Đặt Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Cài Đặt Fabric”">​</a></h1><p>Bài hướng dẫn này sẽ giúp bạn cài đặt Fabric cho trình Launcher Minecraft chính thức.</p><p>Đối với các trình launcher bên thứ ba, bạn nên tham khảo tài liệu của họ.</p><h2 id="_1-tai-xuong-trinh-cai-đat-fabric" tabindex="-1">1. Tải xuống Trình cài đặt Fabric <a class="header-anchor" href="#_1-tai-xuong-trinh-cai-đat-fabric" aria-label="Permalink to “1. Tải xuống Trình cài đặt Fabric”">​</a></h2><p>Bạn có thể tải trình cài đặt Fabric từ <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">trang chủ Fabric</a>.</p><p>Nếu bạn sử dụng Windows, hãy tải phiên bản có đuôi <code>.exe</code> (<code>Download For Windows</code>), bởi vì nó không yêu cầu Java phải được cài trước đó trên hệ thống của bạn. Nó sẽ sử dụng phiên bản Java đi cùng trình launcher chính thức.</p><p>Đối với macOS và Linux, bạn nên tải phiên bản có đuôi <code>.jar</code>. Đôi khi, cách này sẽ yêu cầu Java phải được cài đặt trước đó.</p><h2 id="_2-chay-trinh-cai-đat-fabric" tabindex="-1">2. Chạy Trình cài đặt Fabric <a class="header-anchor" href="#_2-chay-trinh-cai-đat-fabric" aria-label="Permalink to “2. Chạy Trình cài đặt Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Hãy đóng Minecraft và trình Launcher của Minecraft trước khi cài đặt.</p></div><details class="details custom-block"><summary>Thông tin cho người dùng MacOS</summary><p>Trên macOS, bạn có thể cần bấm chuột phải vào tập tin <code>.jar</code> trong thư mục tải xuống của mình và bấm <code>Open</code> để chạy nó.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Trình cài đặt Fabric với chữ &quot;Cài đặt&quot; được tô đậm" loading="lazy"></p><p>Khi được hỏi &quot;Bạn có muốn mở nó không?&quot;, bấm <code>Open</code> lần nữa.</p></details><p>Ngay khi bạn mở trình cài đặt, bạn sẽ thấy màn hình như thế này:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Trình cài đặt Fabric với chữ &quot;Cài đặt&quot; được tô đậm" loading="lazy"></p><p>Để cài đặt Fabric, hãy chọn phiên bản trò chơi bạn muốn từ danh sách thả xuống, và bấm <code>install</code>.</p><p><strong>Hãy đảm bảo đã chọn &#39;Create Profile&#39;.</strong></p><h2 id="_3-hoan-tat" tabindex="-1">3. Hoàn tất! <a class="header-anchor" href="#_3-hoan-tat" aria-label="Permalink to “3. Hoàn tất!”">​</a></h2><p>Sau khi trình cài đặt hoàn tất, bạn có thể mở trình Launcher Minecraft và chọn hồ sơ Fabric từ danh sách thả xuống ở góc trái bên dưới và bấm nút Chơi!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Trình Launcher Minecraft với hồ sơ Fabric được chọn" loading="lazy"></p><h2 id="buoc-tiep-theo" tabindex="-1">Bước Tiếp Theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to “Bước Tiếp Theo”">​</a></h2><p>Bây giờ bạn đã hoàn tất việc cài Fabric, bạn có thể thêm mod vào trong trò chơi! Check out the <a href="./finding-mods">Finding Mods</a> guide for more information.</p><p>Nếu bạn gặp bất cứ vấn đề nào khi đang làm theo bài hướng dẫn này, bạn có thể xin sự trợ giúp từ kênh <code>#player-support</code> trong <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord Fabric</a>.</p>`,20)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};